import React, { useRef, useEffect, useCallback } from 'react';

const DRIFT_THRESHOLD  = 0.08;
const SYNC_INTERVAL_MS = 500;

const VideoAudioPlayer = ({ src, id, activeAudioId, onVisibilityChange }) => {
  const videoRef     = useRef(null);
  const audioRef     = useRef(null);
  const containerRef = useRef(null);
  const syncRef      = useRef(null);
  const isActive     = activeAudioId === id;
  const audioSrc     = src.replace(/\.(mp4|webm)(\?.*)?$/i, '.mp3$2');

  const startSync = useCallback(() => {
    clearInterval(syncRef.current);
    syncRef.current = setInterval(() => {
      const v = videoRef.current, a = audioRef.current;
      if (!v || !a || v.paused || a.paused) return;
      if (Math.abs(v.currentTime - a.currentTime) > DRIFT_THRESHOLD)
        a.currentTime = v.currentTime;
    }, SYNC_INTERVAL_MS);
  }, []);

  const stopSync = useCallback(() => clearInterval(syncRef.current), []);

  // Audio control
  useEffect(() => {
    const audio = audioRef.current, video = videoRef.current;
    if (!audio || !video) return;
    if (isActive) {
      audio.currentTime = video.currentTime;
      audio.play().catch(() => {});
      startSync();
    } else {
      audio.pause();
      stopSync();
    }
    return () => stopSync();
  }, [isActive, startSync, stopSync]);

  // Intersection observer
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => onVisibilityChange(id, e.isIntersecting && e.intersectionRatio > 0.5),
      { threshold: 0.5 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [id, onVisibilityChange]);

  return (
    <div ref={containerRef} style={{ overflowAnchor: 'none' }}>
      <video
        ref={videoRef}
        src={src}
        autoPlay
        loop
        muted
        playsInline
        style={{ width: '100%', height: 'auto', display: 'block' }}
      />
      <audio
        ref={audioRef}
        src={audioSrc}
        loop
        preload="auto"
        style={{ position: 'absolute', left: '-9999px' }}
        tabIndex="-1"
      />
    </div>
  );
};

export default VideoAudioPlayer;
